    name: 'Khalid ibn al-Walid',
    arabicName: 'خَالِدُ بْنُ الوَلِيد',
    era: 'sahabah',
    title: 'Sayf Allah al-Maslul, The Drawn Sword of Allah',
    lifespan: '585 CE - 642 CE',
